        create_cell("markdown", "# 🫀 Heart Disease Prediction - Comprehensive Machine Learning Pipeline (V1 & V2 Optimized)\nThis notebook contains the complete, end-to-end pipeline for the Heart Disease Prediction project. It spans two major versions:\n1. **V1 (Baseline):** Handcoded models, evaluation, threshold tuning, and ensemble stacking.\n2. **V2 (Optimized):** Bayesian hyperparameter optimization using **Optuna** for XGBoost, LightGBM, Random Forest, and MLP, followed by Stacking Ensemble V2, Learning Curves, Explainable AI (SHAP & PDP), Feature Importance comparison, and Patient Clustering for Power BI."),
        
        create_cell("markdown", "## 1. Import Libraries"),
        create_cell("code", "import pandas as pd\nimport numpy as np\nimport matplotlib.pyplot as plt\nimport seaborn as sns\nimport warnings\nimport time\nimport joblib\nimport shap\nimport os\nimport optuna\n\nwarnings.filterwarnings('ignore')\noptuna.logging.set_verbosity(optuna.logging.WARNING)\n\nfrom sklearn.model_selection import train_test_split, StratifiedKFold, cross_val_score, learning_curve\nfrom sklearn.preprocessing import StandardScaler\nfrom sklearn.metrics import classification_report, confusion_matrix, roc_auc_score, f1_score, precision_score, recall_score, roc_curve, precision_recall_curve, auc, accuracy_score, average_precision_score, ConfusionMatrixDisplay\nfrom sklearn.cluster import KMeans\nfrom sklearn.inspection import PartialDependenceDisplay, permutation_importance\nfrom imblearn.over_sampling import SMOTE\n\n# Machine Learning Models\nfrom sklearn.linear_model import LogisticRegression\nfrom sklearn.ensemble import RandomForestClassifier, StackingClassifier\nfrom xgboost import XGBClassifier\nfrom lightgbm import LGBMClassifier\nfrom sklearn.neural_network import MLPClassifier\n\nos.makedirs('outputs', exist_ok=True)\nos.makedirs('outputs/v2', exist_ok=True)"),

        create_cell("markdown", "## 2. Load Dataset"),
