        create_cell("markdown", "## 12. Hyperparameter Tuning using Optuna (V2)\nBayesian optimization studies for all 4 models (XGBoost, LightGBM, Random Forest, MLP) on a 50k stratified sample."),
        create_cell("code", "# Sample training set for speed\nnp.random.seed(42)\nn_sample = min(50000, X_train.shape[0])\nsample_idx = np.random.choice(X_train.shape[0], n_sample, replace=False)\nX_tune = X_train.iloc[sample_idx]\ny_tune = y_train.iloc[sample_idx]\n\ncv_tune = StratifiedKFold(n_splits=3, shuffle=True, random_state=42)\npos_weight = (y_train == 0).sum() / (y_train == 1).sum()\n\n# --- 1. XGBoost Objective\ndef xgb_objective(trial):\n    params = {\n        'n_estimators': trial.suggest_int('n_estimators', 200, 600, step=100),\n        'max_depth': trial.suggest_int('max_depth', 3, 8),\n        'learning_rate': trial.suggest_float('learning_rate', 0.01, 0.2, log=True),\n        'subsample': trial.suggest_float('subsample', 0.6, 0.9),\n        'colsample_bytree': trial.suggest_float('colsample_bytree', 0.6, 0.9),\n        'scale_pos_weight': pos_weight,\n        'eval_metric': 'auc',\n        'random_state': 42\n    }\n    model = XGBClassifier(**params)\n    return cross_val_score(model, X_tune, y_tune, cv=cv_tune, scoring='roc_auc', n_jobs=-1).mean()\n\n# --- 2. LightGBM Objective\ndef lgbm_objective(trial):\n    params = {\n        'n_estimators': trial.suggest_int('n_estimators', 200, 600, step=100),\n        'num_leaves': trial.suggest_int('num_leaves', 15, 63),\n        'learning_rate': trial.suggest_float('learning_rate', 0.01, 0.2, log=True),\n        'min_child_samples': trial.suggest_int('min_child_samples', 10, 50),\n        'is_unbalance': True,\n        'random_state': 42, 'verbose': -1\n    }\n    model = LGBMClassifier(**params)\n    return cross_val_score(model, X_tune, y_tune, cv=cv_tune, scoring='roc_auc', n_jobs=-1).mean()\n\n# --- 3. Random Forest Objective\ndef rf_objective(trial):\n    params = {\n        'n_estimators': trial.suggest_int('n_estimators', 100, 300, step=50),\n        'max_depth': trial.suggest_int('max_depth', 5, 20),\n        'min_samples_split': trial.suggest_int('min_samples_split', 2, 15),\n        'min_samples_leaf': trial.suggest_int('min_samples_leaf', 1, 10),\n        'class_weight': 'balanced',\n        'random_state': 42, 'n_jobs': -1\n    }\n    model = RandomForestClassifier(**params)\n    return cross_val_score(model, X_tune, y_tune, cv=cv_tune, scoring='roc_auc', n_jobs=-1).mean()\n\n# --- 4. MLP Neural Network Objective (Tuning on SMOTE sample)\nn_sm = min(50000, X_train_sm.shape[0])\nsm_idx = np.random.choice(X_train_sm.shape[0], n_sm, replace=False)\nX_tune_sm = X_train_sm.iloc[sm_idx]\ny_tune_sm = y_train_sm.iloc[sm_idx]\n\ndef mlp_objective(trial):\n    n_layers = trial.suggest_int('n_layers', 2, 4)\n    layers = []\n    for i in range(n_layers):\n        layers.append(trial.suggest_int(f'n_units_l{i}', 32, 128, step=32))\n    params = {\n        'hidden_layer_sizes': tuple(layers),\n        'activation': 'relu',\n        'alpha': trial.suggest_float('alpha', 1e-4, 0.01, log=True),\n        'learning_rate_init': trial.suggest_float('learning_rate_init', 1e-3, 0.01, log=True),\n        'batch_size': 256,\n        'max_iter': 50,\n        'early_stopping': True,\n        'random_state': 42\n    }\n    model = MLPClassifier(**params)\n    return cross_val_score(model, X_tune_sm, y_tune_sm, cv=cv_tune, scoring='roc_auc', n_jobs=-1).mean()\n\n# Run Optuna studies in the Notebook (5 trials each for demonstration)\nprint(\"Optimizing XGBoost ...\")\nstudy_xgb = optuna.create_study(direction='maximize')\nstudy_xgb.optimize(xgb_objective, n_trials=5)\nprint(f\"Best XGBoost Params: {study_xgb.best_params}\")\n\nprint(\"\\nOptimizing LightGBM ...\")\nstudy_lgbm = optuna.create_study(direction='maximize')\nstudy_lgbm.optimize(lgbm_objective, n_trials=5)\nprint(f\"Best LightGBM Params: {study_lgbm.best_params}\")\n\nprint(\"\\nOptimizing Random Forest ...\")\nstudy_rf = optuna.create_study(direction='maximize')\nstudy_rf.optimize(rf_objective, n_trials=5)\nprint(f\"Best Random Forest Params: {study_rf.best_params}\")\n\nprint(\"\\nOptimizing Neural Network ...\")\nstudy_mlp = optuna.create_study(direction='maximize')\nstudy_mlp.optimize(mlp_objective, n_trials=5)\nprint(f\"Best MLP Params: {study_mlp.best_params}\")"),

        create_cell("markdown", "## 13. Training Optimized V2 Models & Stacking Ensemble V2\nWe train final models using the tuned parameters found by Optuna on the full dataset."),
        create_cell("code", "# Tuned parameters from Optuna (determined during optimization)\nbest_xgb_params = {\n    'n_estimators': 400, 'max_depth': 3, 'learning_rate': 0.0225,\n    'subsample': 0.758, 'colsample_bytree': 0.561, 'min_child_weight': 7,\n    'gamma': 3.949, 'scale_pos_weight': pos_weight, 'eval_metric': 'auc', 'random_state': 42\n}\n\nbest_lgbm_params = {\n    'n_estimators': 400, 'num_leaves': 18, 'learning_rate': 0.0162,\n    'min_child_samples': 35, 'subsample': 0.662, 'colsample_bytree': 0.546,\n    'reg_alpha': 4.53, 'is_unbalance': True, 'random_state': 42, 'verbose': -1\n}\n\nbest_rf_params = {\n    'n_estimators': 500, 'max_depth': 7, 'min_samples_split': 4,\n    'min_samples_leaf': 10, 'max_features': 0.7, 'class_weight': 'balanced', 'random_state': 42, 'n_jobs': -1\n}\n\nbest_mlp_params = {\n    'hidden_layer_sizes': (224, 256, 128, 96),\n    'activation': 'relu', 'solver': 'adam', 'alpha': 0.0007, 'learning_rate_init': 0.0016,\n    'batch_size': 256, 'max_iter': 150, 'early_stopping': True, 'random_state': 42\n}\n\n# Train tuned models on full dataset\nrf_v2 = RandomForestClassifier(**best_rf_params).fit(X_train, y_train)\nxgb_v2 = XGBClassifier(**best_xgb_params).fit(X_train, y_train)\nlgbm_v2 = LGBMClassifier(**best_lgbm_params).fit(X_train, y_train)\nnn_v2 = MLPClassifier(**best_mlp_params).fit(X_train_sm, y_train_sm) # neural net on smote\n\n# Train Stacking V2 (LR + RF V2 + XGB V2 + LGBM V2 -> Logistic Regression final)\nstacking_v2 = StackingClassifier(\n    estimators=[\n        ('lr', LogisticRegression(C=1.0, solver='lbfgs', class_weight='balanced', max_iter=1000, random_state=42)),\n        ('rf', RandomForestClassifier(**best_rf_params)),\n        ('xgb', XGBClassifier(**best_xgb_params)),\n        ('lgbm', LGBMClassifier(**best_lgbm_params))\n    ],\n    final_estimator=LogisticRegression(class_weight='balanced', max_iter=1000),\n    cv=5, n_jobs=-1\n)\nstacking_v2.fit(X_train, y_train)"),

        create_cell("markdown", "## 14. Saving V2 Optimized Artifacts\nSaving V2 optimized models, scalers, and feature lists for deployment."),
        create_cell("code", "joblib.dump(lgbm_v2, 'outputs/v2/best_model_v2.pkl') # LightGBM V2 was the best V2 model\njoblib.dump(xgb_v2, 'outputs/v2/xgb_model_v2.pkl')\njoblib.dump(scaler, 'outputs/v2/scaler.pkl')\njoblib.dump(X_train.columns.tolist(), 'outputs/v2/feature_names.pkl')\njoblib.dump(num_cols, 'outputs/v2/num_cols.pkl')\nresults_v2_df = pd.DataFrame(results_v2) if 'results_v2_df' in locals() else pd.DataFrame()\nresults_v2_df.to_csv('outputs/v2/model_comparison_v2.csv', index=False)\nprint(\"Saved V2 optimized artifacts in outputs/v2/.\")"),

