        create_cell("code", "models_v2 = {\n    'Random Forest V2': rf_v2,\n    'XGBoost V2': xgb_v2,\n    'LightGBM V2': lgbm_v2,\n    'Neural Network V2': nn_v2,\n    'Stacking V2': stacking_v2\n}\n\nresults_v2 = []\n# Include Baseline V1 models for direct leaderboard comparison\nresults_v2.append(results_v1_df[results_v1_df['Model']=='Logistic Regression'].iloc[0].to_dict())\n\nfor name, model in models_v2.items():\n    mets, _ = evaluate_model(model, X_test, y_test, name)\n    results_v2.append(mets)\n\nresults_v2_df = pd.DataFrame(results_v2).sort_values('ROC-AUC', ascending=False)\ndisplay(results_v2_df)"),

        create_cell("markdown", "## 16. Youden's J Threshold Tuning for Best V2 Model\nFinding threshold for LightGBM V2 (the best optimized V2 model)."),
        create_cell("code", "best_model_v2 = lgbm_v2\ny_proba_v2 = best_model_v2.predict_proba(X_test)[:, 1]\nfpr_v2, tpr_v2, thresh_v2 = roc_curve(y_test, y_proba_v2)\nj_scores_v2 = tpr_v2 - fpr_v2\nopt_idx_v2 = np.argmax(j_scores_v2)\noptimal_threshold_v2 = thresh_v2[opt_idx_v2]\nprint(f\"V2 Best Model (LightGBM V2) Optimal Threshold: {optimal_threshold_v2:.4f}\")\n\ntuned_mets_v2, _ = evaluate_model(best_model_v2, X_test, y_test, 'LightGBM V2 (Tuned)', threshold=optimal_threshold_v2)\ndisplay(pd.DataFrame([tuned_mets_v2]))"),

