        create_cell("code", "cv5 = StratifiedKFold(n_splits=5, shuffle=True, random_state=42)\ncv_scores_v2 = cross_val_score(best_model_v2, X_train, y_train, cv=cv5, scoring='roc_auc', n_jobs=-1)\nprint(f\"V2 Best Model CV ROC-AUC: {cv_scores_v2.mean():.4f} +/- {cv_scores_v2.std():.4f}\")"),

        create_cell("markdown", "## 18. V1 Baseline vs V2 Optimized Side-by-Side Comparison"),
        create_cell("code", "v1_best = results_v1_df.iloc[0]\nv2_best = results_v2_df.iloc[0]\n\nprint(f\"★ V1 Best Model ({v1_best['Model']}) ROC-AUC: {v1_best['ROC-AUC']:.4f}\")\nprint(f\"★ V2 Best Model ({v2_best['Model']}) ROC-AUC: {v2_best['ROC-AUC']:.4f}\")\nprint(f\"★ Absolute AUC Improvement: {v2_best['ROC-AUC'] - v1_best['ROC-AUC']:+.4f}\")\n\nmetrics_to_compare = ['ROC-AUC', 'PR-AUC', 'F1-Score', 'Recall', 'Precision', 'Accuracy']\nfig, ax = plt.subplots(figsize=(10, 5))\nx = np.arange(len(metrics_to_compare))\nwidth = 0.35\nv1_vals = [v1_best[m] for m in metrics_to_compare]\nv2_vals = [v2_best[m] for m in metrics_to_compare]\n\nrects1 = ax.bar(x - width/2, v1_vals, width, label=f\"V1: {v1_best['Model']}\", color='#90CAF9', edgecolor='#1565C0')\nrects2 = ax.bar(x + width/2, v2_vals, width, label=f\"V2: {v2_best['Model']}\", color='#EF9A9A', edgecolor='#C62828')\n\nax.set_xticks(x)\nax.set_xticklabels(metrics_to_compare)\nax.set_ylabel('Score')\nax.set_title('V1 Baseline vs V2 Optimized — Best Model Comparison')\nax.set_ylim(0, 1.15)\nax.legend()\n\nfor rect in rects1 + rects2:\n    h = rect.get_height()\n    ax.annotate(f'{h:.3f}', xy=(rect.get_x() + rect.get_width()/2, h),\n                xytext=(0, 3), textcoords='offset points', ha='center', va='bottom', fontsize=8)\nplt.tight_layout()\nplt.show()"),

        create_cell("markdown", "## 19. Learning Curves\nDiagnostic plot to verify generalizability of the tuned model."),
